+        project_key: "/test/project",
+        program: "vitest",
+        model: "v1",
+        name: "TestAgent",
+      });
+
+      const result = await toolsCall("register_agent", {
+        project_key: "/test/project",
+        program: "vitest",
+        model: "v2",
+        name: "TestAgent",
