+  // ============================================================================
+
+  describe("send_message", () => {
+    beforeEach(async () => {
+      await toolsCall("ensure_project", { human_key: "/test/project" });
+      await toolsCall("register_agent", {
+        project_key: "/test/project",
+        program: "test",
+        model: "test",
+        name: "Sender",
